/// `POST /api/projects/clone` — clone a GitHub repository and register it.
///
/// Accepts a GitHub URL, shorthand (`owner/repo`), HTTPS URL, or SSH URL.
/// If a GitHub token is connected, it is injected for authentication.
///
/// **Request body:**
/// ```json
/// { "repo_url": "https://github.com/owner/repo" }
/// ```
///
/// **Response:** `201 Created` with the created `Project` as JSON.
///
/// **Errors:**
/// - `400 Bad Request` if the URL is unparseable or `git clone` fails
/// - `500 Internal Server Error` on filesystem or DB errors
async fn clone_project(
    State(state): State<SharedState>,
    Json(req): Json<CloneProjectRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let repo_url = req.repo_url.trim().to_string();

    // Parse repo name from URL (handles https://github.com/user/repo, user/repo, etc.)
    let repo_name = repo_url
        .trim_end_matches('/')
        .trim_end_matches(".git")
        .rsplit('/')
        .next()
        .ok_or_else(|| ApiError::BadRequest("Invalid repository URL".to_string()))?
        .to_string();

    if repo_name.is_empty() {
        return Err(ApiError::BadRequest(
            "Could not parse repository name from URL".to_string(),
        ));
    }

    // Normalize: if it looks like "user/repo", prepend GitHub URL
    let clone_url = if repo_url.starts_with("http://")
        || repo_url.starts_with("https://")
        || repo_url.starts_with("git@")
    {
        repo_url.clone()
    } else {
        format!("https://github.com/{}", repo_url)
    };

    // If we have a GitHub token, use it for cloning (enables private repos)
    let (clone_url, token) = {
        let gh_token = state
            .github_token
            .lock()
            .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?;
        if let Some(ref t) = *gh_token {
            if clone_url.starts_with("https://github.com/") {
                (
                    clone_url.replacen(
                        "https://github.com/",
                        &format!("https://x-access-token:{}@github.com/", t),
                        1,
                    ),
                    Some(t.clone()),
                )
            } else {
                (clone_url, Some(t.clone()))
            }
        } else {
            (clone_url, None)
        }
    };

    // Clone into .forge/repos/<repo_name>
    let repos_dir = std::path::PathBuf::from(".forge/repos");
    tokio::fs::create_dir_all(&repos_dir)
        .await
        .map_err(|e| ApiError::Internal(format!("Failed to create repos directory: {}", e)))?;

    let clone_path = repos_dir.join(&repo_name);
    let already_cloned = clone_path.exists();

    if !already_cloned {
        let clone_path_str = clone_path.to_string_lossy().to_string();

        // Run git clone asynchronously
        let output = tokio::process::Command::new("git")
            .args(["clone", &clone_url, &clone_path_str])
            .output()
            .await
            .map_err(|e| ApiError::Internal(format!("Failed to run git clone: {}", e)))?;

        if !output.status.success() {
            let stderr = String::from_utf8_lossy(&output.stderr);
            let sanitized_stderr = if let Some(ref t) = token {
                stderr.trim().replace(t, "***")
            } else {
                stderr.trim().to_string()
            };
            return Err(ApiError::BadRequest(format!(
                "git clone failed: {}",
                sanitized_stderr
            )));
        }

        // After successful clone, strip token from remote URL to prevent leaking
        if token.is_some() {
            let output = tokio::process::Command::new("git")
                .args(["remote", "set-url", "origin", &repo_url])
                .current_dir(&clone_path_str)
                .output()
                .await;
            match output {
                Ok(o) if !o.status.success() => {
                    tracing::warn!(stderr = %String::from_utf8_lossy(&o.stderr), "Failed to strip auth token from git remote URL");
                }
                Err(e) => {
                    tracing::warn!(error = %e, "Failed to strip auth token from git remote URL");
                }
                Ok(_) => {}
            }
        }
    }

    // Resolve to absolute path for the project record
    let abs_path = tokio::fs::canonicalize(&clone_path)
        .await
        .map_err(|e| ApiError::Internal(format!("Failed to resolve path: {}", e)))?;
    let abs_path_str = abs_path.to_string_lossy().to_string();

    // Parse the GitHub owner/repo from the original URL (before token injection)
    let github_repo = parse_github_owner_repo(&repo_url);

    let project = {
        // Check if a project already exists for this path
        let existing = state
            .db
            .list_projects()
            .await
            .map_err(|e| ApiError::Internal(e.to_string()))?
            .into_iter()
            .find(|p| p.path == abs_path_str);

        let project = if let Some(project) = existing {
            project
        } else {
            state
                .db
                .create_project(&repo_name, &abs_path_str)
                .await
                .map_err(|e| ApiError::Internal(e.to_string()))?
        };

        // Store the GitHub owner/repo
        if let Some(ref owner_repo) = github_repo {
            state
                .db
                .update_project_github_repo(project.id, owner_repo)
                .await
                .map_err(|e| ApiError::Internal(e.to_string()))?
        } else {
            project
        }
    };

    broadcast_message(
        &state.ws_tx,
        &WsMessage::ProjectCreated {
            project: project.clone(),
        },
    );

    // Auto-sync GitHub issues in the background
    if github_repo.is_some() {
        let state_clone = Arc::clone(&state);
        let pid = project.id;
        tokio::spawn(async move {
            tokio::time::sleep(std::time::Duration::from_millis(500)).await;
            match do_sync_github_issues(&state_clone, pid).await {
                Ok(result) => {
                    tracing::info!(
                        imported = result.imported,
                        project_id = pid.0,
                        "Auto-synced GitHub issues"
                    );
                }
                Err(e) => {
                    let detail = match e {
                        ApiError::Internal(msg)
                        | ApiError::BadRequest(msg)
                        | ApiError::NotFound(msg) => msg,
                    };
                    tracing::error!(project_id = pid.0, error = %detail, "Auto-sync GitHub issues failed");
                }
            }
        });
    }

    Ok((StatusCode::CREATED, Json(project)))
}

