/// `PATCH /api/issues/:id/move` — move an issue to a different column and position.
///
/// **Request body:**
/// ```json
/// { "column": "in_progress", "position": 0 }
/// ```
///
/// Broadcasts an `IssueMoved` WebSocket message with `from_column`, `to_column`, `position`.
///
/// **Errors:**
/// - `400 Bad Request` if the column name is invalid
async fn move_issue(
    State(state): State<SharedState>,
    Path(id): Path<i64>,
    Json(req): Json<MoveIssueRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let column = IssueColumn::from_str(&req.column).map_err(ApiError::BadRequest)?;
    let position = req.position;
    // Note: from_column may be stale if another request moves the issue concurrently.
    // This only affects the WebSocket broadcast animation, not data integrity.
    let from_column = state
        .db
        .get_issue(IssueId(id))
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?
        .map(|i| i.column.as_str().to_string())
        .unwrap_or_default();
    let issue = state
        .db
        .move_issue(IssueId(id), &column, position)
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;
    broadcast_message(
        &state.ws_tx,
        &WsMessage::IssueMoved {
            issue_id: IssueId(id),
            from_column,
            to_column: req.column.clone(),
            position: req.position,
        },
    );
    Ok(Json(issue))
}

