        let task_w0_updated = db.get_agent_task(task_w0.id).await?;
        assert_eq!(task_w0_updated.status, AgentTaskStatus::Failed);
        assert_eq!(task_w0_updated.error.as_deref(), Some("test error"));

        Ok(())
    }

