    }

    impl MockTaskRunner {
        fn all_succeed() -> Self {
            Self {
                results: std::sync::Mutex::new(HashMap::new()),
                merge_results: std::sync::Mutex::new(HashMap::new()),
            }
        }

        #[allow(dead_code)]
        fn with_task_result(self, task_name: &str, success: bool) -> Self {
            self.results
                .lock()
                .unwrap()
                .insert(task_name.to_string(), success);
