189→    /// Aggregate run statistics over the last `days` days; rate fields are in [0.0, 1.0].
190→    pub async fn summary_stats(&self, days: u32) -> Result<queries::SummaryStats> {
191→        let days = days as i64;
192→        self.db
193→            .call(move |db| {
194→                let row = db.conn.query_row(
195→                    "SELECT \
196→                    COUNT(*) as total_runs, \
197→                    COALESCE(SUM(CASE WHEN success = 1 THEN 1 ELSE 0 END), 0) as successful_runs, \
198→                    COALESCE(AVG(duration_secs), 0.0) as avg_duration \
199→                 FROM metrics_runs \
200→                 WHERE started_at >= datetime('now', '-' || ?1 || ' days')",
201→                    params![days],
202→                    |row| {
203→                        Ok((
204→                            row.get::<_, i64>(0)?,
205→                            row.get::<_, i64>(1)?,
206→                            row.get::<_, f64>(2)?,
207→                        ))
208→                    },
209→                )?;
210→
211→                let (total_phases, avg_iters): (i64, f64) = db.conn.query_row(
212→                    "SELECT COUNT(*), COALESCE(AVG(iterations_used), 0.0) \
213→                 FROM metrics_phases mp \
214→                 JOIN metrics_runs mr ON mp.run_id = mr.run_id \
215→                 WHERE mr.started_at >= datetime('now', '-' || ?1 || ' days')",
216→                    params![days],
217→                    |row| Ok((row.get(0)?, row.get(1)?)),
218→                )?;
219→
220→                let success_rate = if row.0 > 0 {
221→                    row.1 as f64 / row.0 as f64
222→                } else {
223→                    0.0
224→                };
225→
226→                Ok(queries::SummaryStats {
227→                    total_runs: row.0,
228→                    successful_runs: row.1,
229→                    success_rate,
230→                    avg_duration_secs: row.2,
231→                    total_phases,
232→                    avg_iterations_per_phase: avg_iters,
233→                })
234→            })
235→            .await
236→    }
