238→    /// Per-phase-name statistics over the last `days` days; rate fields are in [0.0, 1.0].
239→    pub async fn phase_stats_by_name(&self, days: u32) -> Result<Vec<queries::PhaseNameStats>> {
240→        let days = days as i64;
241→        self.db.call(move |db| {
242→            let mut stmt = db.conn.prepare(
243→                "SELECT \
244→                    phase_name, \
245→                    COUNT(*) as run_count, \
246→                    COALESCE(AVG(CAST(iterations_used AS REAL)), 0.0) as avg_iterations, \
247→                    COALESCE(AVG(mp.duration_secs), 0.0) as avg_duration, \
248→                    COALESCE(AVG(CAST(iterations_used AS REAL) / NULLIF(CAST(budget AS REAL), 0.0)), 0.0) as budget_util, \
249→                    COALESCE(AVG(CASE WHEN outcome = 'completed' THEN 1.0 ELSE 0.0 END), 0.0) as success_rate \
250→                 FROM metrics_phases mp \
251→                 JOIN metrics_runs mr ON mp.run_id = mr.run_id \
252→                 WHERE mr.started_at >= datetime('now', '-' || ?1 || ' days') \
253→                 GROUP BY phase_name \
254→                 ORDER BY run_count DESC"
255→            )?;
256→            let rows = stmt.query_map(params![days], |row| {
257→                Ok(queries::PhaseNameStats {
258→                    phase_name: row.get(0)?,
259→                    run_count: row.get(1)?,
260→                    avg_iterations: row.get(2)?,
261→                    avg_duration_secs: row.get(3)?,
262→                    budget_utilization: row.get(4)?,
263→                    success_rate: row.get(5)?,
264→                })
265→            })?;
266→            rows.collect::<std::result::Result<Vec<_>, _>>().map_err(Into::into)
267→        }).await
268→    }
