286→            )?;
287→            let rows = stmt.query_map(params![days], |row| {
288→                Ok(queries::ReviewStats {
289→                    specialist_type: row.get(0)?,
290→                    total_reviews: row.get(1)?,
291→                    pass_rate: row.get(2)?,
292→                    avg_findings: row.get(3)?,
293→                    avg_critical: row.get(4)?,
294→                })
295→            })?;
296→            rows.collect::<std::result::Result<Vec<_>, _>>().map_err(Into::into)
297→        }).await
298→    }
