            .record_compaction("comp-run", 1, 2, 50000, 15000, 0.3)
            .await
            .unwrap();
        // Verify it was inserted
        let count: i64 = db
            .call(|db| {
                Ok(db
                    .conn
                    .query_row("SELECT count(*) FROM metrics_compactions", [], |row| {
                        row.get(0)
                    })?)
            })
            .await
            .unwrap();
        assert_eq!(count, 1);
    }

