use std::str::FromStr;

use anyhow::{Context, Result};
use libsql::{Connection, Row};

use crate::factory::models::*;

use super::pipeline::{RUN_COLS, row_to_pipeline_run};

fn row_to_issue(row: &Row) -> Result<Issue> {
    let column_name: String = row.get(4)?;
    let priority_str: String = row.get(6)?;
    let labels_str: String = row.get(7)?;

    let column = IssueColumn::from_str(&column_name)
        .map_err(|e| anyhow::anyhow!(e))
        .context("Failed to parse issue column")?;
    let priority = Priority::from_str(&priority_str)
        .map_err(|e| anyhow::anyhow!(e))
        .context("Failed to parse issue priority")?;
    let labels: Vec<String> =
        serde_json::from_str(&labels_str).context("Failed to parse issue labels JSON")?;

    Ok(Issue {
        id: IssueId(row.get::<i64>(0)?),
        project_id: ProjectId(row.get::<i64>(1)?),
        title: row.get(2)?,
        description: row.get(3)?,
        column,
        position: row.get(5)?,
        priority,
        labels,
        github_issue_number: row.get(8)?,
        created_at: row.get(9)?,
        updated_at: row.get(10)?,
    })
}

const ISSUE_COLS: &str = "id, project_id, title, description, column_name, position, priority, labels, github_issue_number, created_at, updated_at";

pub async fn create_issue(
    conn: &Connection,
    project_id: ProjectId,
    title: &str,
    description: &str,
    column: &IssueColumn,
) -> Result<Issue> {
    let tx = conn
        .transaction()
        .await
        .context("Failed to begin transaction")?;
    let mut rows = tx
        .query(
            "SELECT COALESCE(MAX(position), -1) FROM issues WHERE project_id = ?1 AND column_name = ?2",
            (project_id.0, column.as_str()),
        )
        .await
        .context("Failed to get max position")?;
    let max_pos: i32 = match rows.next().await? {
        Some(row) => row.get(0)?,
        None => -1,
    };
    let position = max_pos + 1;
    tx.execute(
        "INSERT INTO issues (project_id, title, description, column_name, position) VALUES (?1, ?2, ?3, ?4, ?5)",
        libsql::params![project_id.0, title, description, column.as_str(), position],
    )
    .await
    .context("Failed to insert issue")?;
    let id = IssueId(tx.last_insert_rowid());
    tx.commit().await.context("Failed to commit")?;
    get_issue(conn, id)
        .await?
        .context("Issue not found after insert")
}

pub async fn list_issues(conn: &Connection, project_id: ProjectId) -> Result<Vec<Issue>> {
    let sql = format!(
        "SELECT {} FROM issues WHERE project_id = ?1 AND deleted_at IS NULL ORDER BY position",
        ISSUE_COLS

use serde::Serialize;

#[derive(Debug, Clone, Serialize)]
pub struct SummaryStats {
    pub total_runs: i64,
    pub successful_runs: i64,
    /// Ratio of successful runs to total runs, in [0.0, 1.0].
    pub success_rate: f64,
    pub avg_duration_secs: f64,
    pub total_phases: i64,
    pub avg_iterations_per_phase: f64,
}

#[derive(Debug, Clone, Serialize)]
pub struct PhaseNameStats {
    pub phase_name: String,
    pub run_count: i64,
    pub avg_iterations: f64,
    pub avg_duration_secs: f64,
    /// Ratio of iterations used to budget, in [0.0, 1.0].
    pub budget_utilization: f64,
    pub success_rate: f64,
}

#[derive(Debug, Clone, Serialize)]
pub struct ReviewStats {
    pub specialist_type: String,
    pub total_reviews: i64,
    /// Ratio of reviews with verdict "pass" to total reviews, in [0.0, 1.0].
    pub pass_rate: f64,
    pub avg_findings: f64,
    pub avg_critical: f64,
}

#[derive(Debug, Clone, Serialize)]
pub struct RunSummary {
    pub run_id: String,
    pub issue_id: Option<i64>,
    pub success: bool,
    pub duration_secs: Option<f64>,
    pub phases_total: Option<i32>,
    pub started_at: String,
}

#[derive(Debug, Clone, Serialize)]
pub struct TokenDailyUsage {
    pub date: String,
    pub total_input_tokens: i64,
    pub total_output_tokens: i64,
}

///
/// Supports three modes:
/// - **Local SQLite** (dev/offline fallback)
/// - **Turso embedded replica** with local cache and sync
/// - **Turso remote HTTP** (pure HTTP, no local cache — fallback when replica handshake fails)
#[derive(Clone)]
pub struct DbHandle {
    db: Arc<Database>,
    /// Shared connection used for all operations.
    /// libsql's `:memory:` databases create a new database per `connect()` call,
    /// so we keep one connection alive and reuse it everywhere.
    ///
    /// Safety: libsql connections are internally synchronized (serialized via mutex),
    /// so sharing a single `Connection` behind `Arc` is safe for concurrent use
    /// across multiple tokio tasks.
    conn: Arc<Connection>,
    mode: DbMode,
}

impl DbHandle {
    /// Open a local-only SQLite database at the given path.
    pub async fn new_local(path: &Path) -> Result<Self> {
        let path_str = path.to_string_lossy().to_string();
        let db = Builder::new_local(&path_str)
            .build()
            .await
            .context("Failed to open local SQLite database")?;
        Self::from_db(db, DbMode::Local).await
    }

